var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이번엔 그쪽으로 간다!","JPN":"今度はそっちに行く！","ENG":"This one’s headed over there!","TWN":"這次往那裡走！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"확인했어! 내가 발사좌표로 유인하지!","JPN":"確認した！　私が発射の座標へと誘導しよう！","ENG":"I see it! I'll lure it to the coordinates!","TWN":"確認完畢！我會將它們引到發射座標！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"놈이 사정권 안으로 들어갔습니다!","JPN":"やつが射程圏内に入りました！","ENG":"The monster's within range, sir!","TWN":"進入射程範圍內！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"지금이다! 발사!","JPN":"今だ！　発射！","ENG":"Now! FIRE!!","TWN":"就是現在！發射！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"방금 그게 마지막 놈이었나?","JPN":"今のが最後か？","ENG":"Was that the last of them?","TWN":"剛才那隻是最後一個嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"아무래도 그런 것 같습니다. 침식파가 더는 감지되지 않아요.","JPN":"どうやらそのようです。もう侵食波が感知されません。","ENG":"I believe so. We’re not sensing any more Corruption ray.","TWN":"好像是，目前沒有再感應到侵蝕波。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"보고도 믿기지 않는군. 저 덩치 큰 놈들을 전부 해치우다니…….","JPN":"この目で見ても信じられないな。あのデカいやつらを全部やっつけるなんて……","ENG":"I can't believe it. We got all of those giant monsters...","TWN":"真不敢置信，竟然把塊頭那麼大的傢伙全都解決掉了……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"헉… 헉… 끝난 건가?","JPN":"はあ……はあ……終わったのか？","ENG":"*Huff... Huff...* Is it over?","TWN":"呼…呼…結束了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식파는 사라졌어. 우리가 모두 처리한 것 같아.","JPN":"侵食波は消えた。すべて片付けたみたい。","ENG":"Corruption ray's gone. I think we got all of them.","TWN":"侵蝕波消失了，好像都解決掉了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그거… 다행이군.","JPN":"それは……良かったな。","ENG":"That's... a relief.","TWN":"那…就好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"혼란스러운 와중에 대원들이 다들 제 역할을 잘 해줬어.","JPN":"混乱してる中でも隊員それぞれが自分の役割をよく果たしてくれた。","ENG":"Everyone did an excellent job despite the chaos.","TWN":"混亂之中隊員們也都有各盡其職，"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"평소에도… 훈련이 잘 되어 있었던 거겠지.","JPN":"普段の……訓練のたまものだろう。","ENG":"I guess... that means they were trained well.","TWN":"應該是…平時就訓練有素吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"겸손 떨 필요 없어.","JPN":"謙遜する必要はない。","ENG":"There no need to be modest.","TWN":"不需要這麼謙虛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신의 지휘가 아니었으면…","JPN":"あなたの指揮がなかったら……","ENG":"If it wasn't for your command─","TWN":"若不是有你的指揮…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…큐리안?","JPN":"……キュリアン？","ENG":"Curian...?","TWN":"…庫里安？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"이해가 안 됩니다.","JPN":"理解できません。","ENG":"I don't understand.","TWN":"我不懂。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"아무리 보안을 위해서라고 하지만 호송하는 병사들도 정체를 모른다니요.","JPN":"いくら保安のためとは言え、護送する兵士にも正体を知らせないなんて。","ENG":"Even if it's for security reasons, how are we supposed to transport something when we have no idea what it is?","TWN":"雖說是因為安全的緣故，可是連負責護送的兵士都被蒙在鼓裡，"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"우리가 지켜야 할 열쇠라는 것이 최소한 어떻게 생겨 먹었는지는 알아야 되지 않습니까?","JPN":"自分たちが守るべきの鍵というものが、せめてどんな形をしているかは知っておくべきではありませんか。","ENG":"Shouldn’t we at least know the shape of this so-called Key that we have to protect?","TWN":"至少我們要知道要護送的鑰匙長什麼樣子吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"지휘권자 외에 성유물을 공개해선 안 된다는 군명이 있기 때문이다.","JPN":"指揮権者以外に聖遺物を公開してはならないという軍名があったからだ。","ENG":"There's a military order that the Holy Relic can’t be disclosed to anyone but the commander.","TWN":"這是軍令規定，不得對指揮官以外之人公開聖遺物。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"어째서입니까? 저희 중에 성유물을 노리는 배반자라도 있다는 뜻입니까?","JPN":"どうしてですか？　我々の中に聖遺物を狙う裏切り者でもいるということですか？","ENG":"But why? Are they implying that one of us may be a traitor trying to steal it?","TWN":"爲什麼？難道意思是，我們之中有覬覦聖遺物的叛徒嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"가능성을 배제할 수는 없겠지.","JPN":"可能性は排除できないだろう。","ENG":"We cannot leave room for uncertainty.","TWN":"不排除有這個可能性。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"이 건에 대해서는 더 이상 논의하지 않겠다. 다들 돌아가라.","JPN":"この件についてはここまでだ。みんな戻れ。","ENG":"I will not discuss this any further. Return to your position.","TWN":"這件事就到此為止，你們都回去吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"총사대장님, 병사들이 불안해하고 있습니다.","JPN":"銃士隊長、兵士たちが不安がっています。","ENG":"Sir, the soldiers are getting anxious.","TWN":"隊長，士兵們都很不安。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"열쇠의 힘을 겪어 본 이상 물욕이 생길 수도 있어.","JPN":"鍵の力を体験した以上、物欲が生じるかもしれない。","ENG":"Once they witnesses the power of the Key, greed might take them over.","TWN":"只要體驗過鑰匙的力量，很可能就會產生貪念。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"무엇인지 모른다면 탐난다고 해도 노릴 수 없지. 내가 바라는 건 오직 그뿐이다.","JPN":"どんなものか知らなければ欲しいと思っても狙えまい。私が望むのはただそれだけだ。","ENG":"However, not knowing what it is makes it harder to steal. That is all I am trying to accomplish.","TWN":"若是不知道，就算有貪念也無法覬覦，我只希望如此。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"……모쪼록 아무 탈 없이 도착하면 좋겠군요.","JPN":"……なんの事件もなく到着するといいですが。","ENG":"I hope we arrive without any issues, sir.","TWN":"……總之希望能順利抵達。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"그래. 다들 같은 생각일 거다.","JPN":"ああ。みんなも同じ思いだろう。","ENG":"Indeed. Everyone should be thinking the same.","TWN":"沒錯，大家應該都是一樣的想法。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"더 이상 절망하는 건, 누구도 바라지 않을 테니까.","JPN":"これ以上の絶望は、誰も望んでいないはずだからな。","ENG":"Nobody here wants to fall into despair again.","TWN":"因為大家都不希望再次經歷絕望。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"여기는……?","JPN":"ここは……？","ENG":"Where am I…?","TWN":"這裡是……？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"병실. 여기서 두 번이나 멀쩡하게 깨어난 건 당신이 처음이야.","JPN":"病室。ここで二度も元気に目覚めたのはあなたが初めてよ。","ENG":"The hospital room. You're the first person to ever wake up fine twice here.","TWN":"病房，你是第一個在這個病房裡二次都順利醒過來的人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"으음……. 어쩌다 또 실려 온 거지?","JPN":"うむ……どうしてまた運ばれてきたんだ？","ENG":"Ugh... How did I get here?","TWN":"嗯……我怎麼又被送來這裡？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"전투가 끝나고 갑자기 쓰러졌어.","JPN":"戦闘が終わって、いきなり倒れたよ。","ENG":"You suddenly fainted after the battle.","TWN":"作戰結束後你突然暈過去。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다른 병사들은? 인명 피해는 없었나?","JPN":"他の兵士は？　人的被害はなかったのか？","ENG":"What about the other soldiers? Were there any casualties?","TWN":"其他士兵呢？有人員傷亡嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신이 전부야. 부상자 1명.","JPN":"あなただけ。怪我人1名。","ENG":"Only one wounded. You.","TWN":"就你一個，傷患1名。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"듣던 중 좋은 소식이군.","JPN":"それはよかったな。","ENG":"That's good news.","TWN":"這真是個天大的好消息。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"안심하긴 아직 일러. 당장 자기가 쓰러진 이유도 모르고 있잖아?","JPN":"安心するにはまだ早い。自分が倒れた理由もわかってないじゃない。","ENG":"Isn't it too early for you to celebrate? You don't even know why you fainted.","TWN":"現在放心還太早，你不是連自己暈倒的原因都不知道嗎?"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"회복도 제대로 못한 상태로 무리를 한 탓이겠지. 전시에는 흔한 일이다.","JPN":"まともに回復できてない状態で無理したせいだろう。戦時にはよくあることだ。","ENG":"I believe it's because I overworked myself without properly recovering. It's normal during battle.","TWN":"可能是因爲沒有好好恢復就勉強上場吧，這在作戰時是常有的事。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런데 몸이 마음대로 움직이지 않는군. 마취가 덜 풀린 건가?","JPN":"ところで、体が思いどおり動かないな。麻酔が残っているのか？","ENG":"But I can't seem to move properly. Is it because of the anesthesia?","TWN":"不過，我的身體怎麼不能動？是麻醉還沒完全退的關係嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"난 마취 같은 거 안 해. 게다가 이번엔 수술 같은 건 하지도 않았어.","JPN":"私は麻酔なんてしない。それに今回はそもそも手術なんてしていないし。","ENG":"I don't do anesthesia. Also, you didn't undergo any surgery this time.","TWN":"我沒在使用麻醉，而且這次也沒動手術。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇다면……?","JPN":"なら……？","ENG":"Then...?","TWN":"那是……？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신. 침식증후군이야.","JPN":"あなた。侵食症候群よ。","ENG":"You have Corruption Syndrome.","TWN":"你，是侵蝕症候群。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그것도 꽤 진행이 된 상태야. 아직 침식체가 되지 않았다는 게 놀라울 정도로.","JPN":"しかもだいぶ進んでる状態。まだ侵食体になってないのが不思議なくらい。","ENG":"And it's progressed pretty far. I'm surprised you're not a C.O. yet.","TWN":"似乎已經蠻長一段時間，令人驚訝的是，你竟然還沒變成侵蝕體。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식체에게 부상당한 인간이 겪는 병을 말하는 건가?","JPN":"侵食体によって負傷した人間がかかる病気のことか？","ENG":"You mean that disease humans get from getting wounded by C.O.s?","TWN":"你是指被侵蝕體弄傷後會得的病嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식체에게 물리지 않아도 돼. 침식 증후군은 침식파에 노출되는 것만으로도 걸리거든.","JPN":"侵食体に噛まれなくてもいい。侵食波に露出するだけでも侵食症候群になるから。","ENG":"You don't have to get bitten by one to get it. Just being exposed to the Corruption ray is enough to get Corruption Syndrome.","TWN":"就算沒有被侵蝕體咬到，只要暴露在侵蝕波裡，就有可能會受到感染。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이렇게 되면 당신이 20년 전 사람이라는 터무니없는 말도 그럴싸해지긴 하지.","JPN":"こうなればあなたが20年前の人間だというとんでもない話も頷ける。","ENG":"This explains how you're a person from 20 years ago.","TWN":"若是如此，你說你是二十年前的人，似乎也並非無稽之談"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식 증후군은 침식 현상만큼 증상이 천차만별이야.","JPN":"侵食症候群は侵食現象のように症状が千差万別よ。","ENG":"Corruption Syndrome, like the Counterside Effect, has a wide range of symptoms.","TWN":"侵蝕症候群和侵蝕現象一樣，會有很多不同的症狀  "},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"바깥 나라에서 보고된 사례 중에는 노화가 지연된 경우도 있었어.","JPN":"国外で報告された事例の中には、老化が遅くなったケースもあった。","ENG":"There have even been reports from other countries that say it has slowed down aging in some cases.","TWN":"根據其他國家提供的案例，延緩老化也可能是症狀之一。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"불로불사는 축복 아닌가?","JPN":"不老不死は祝福ではないのか？","ENG":"Does that mean I'm blessed with immortality?","TWN":"長生不老不是祝福嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그 대신 세포가 정상적으로 사멸되지 않아서 온몸이 종양에 뒤덮인 채로 사망했지.","JPN":"その代わりに、細胞が正常的に死滅しないから全身が腫瘍だらけになって死亡した。","ENG":"However, your cells will not die out normally, and you will die with tumors covering your entire body.","TWN":"但是由於胞無法正常死亡，最後會全身長滿腫瘤而死。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식 증후군이 작용하기 시작하면, 남은 삶은 어떤 식으로든 고통스러울 수밖에 없어.","JPN":"侵食症候群が発症すると、残された人生はどんな形であれ苦しみが伴う。","ENG":"Once the Corruption Syndrome starts, only pain and suffering awaits.","TWN":"侵蝕症候群一旦發作，無論用什麼方法，餘生都只能在痛苦中度過。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 그 사례를 예로 들면, 20년 전 사람이 젊은 시절 그대로인 것도 설명돼.","JPN":"でもあの事例を考えると、20年前の人間が若い頃の姿のままでいるのも説明がつく。","ENG":"However, using that case as an example, it could explain why you look to be the same age as 20 years ago.","TWN":"不過若是以那個案例爲例，就可以證明20年前的人，還是可以維持年輕時的樣貌。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"20년 동안 살아 있었다는 것 자체가 기적이지만.","JPN":"20年間生きているという自体が奇跡だけど。","ENG":"Even so, being alive with it for 20 years is a miracle in itself.","TWN":"能活20年本身就是個奇蹟。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…그렇군.","JPN":"……そうか。","ENG":"I see...","TWN":"…原來如此。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"울고 싶으면 어깨라도 빌려 줘?","JPN":"泣きたいのなら肩でも貸そうか？","ENG":"Would you like a shoulder to cry on?","TWN":"想哭的話，需要我借你肩膀嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아직은 눈물이 안 나는데. 나중에 한 번 더 물어봐 주겠나?","JPN":"まだ涙は出ないな。あとでもう一度聞いてみてくれないか？","ENG":"No tears seem to be coming out today. So, rain check?","TWN":"現在還沒有想哭的感覺，還是你可以晚點再問一次嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"의외로 담담하네. 경멸하던 환자들과 같은 처지가 됐다는 걸 이해 못하는 사람들이 많거든.","JPN":"意外と淡々としているね。軽蔑してた患者と同じになったってことを受け入れられない人が多いけど。","ENG":"You're oddly calm. I've seen many who can't wrap their head around the fact that they've become exactly like the patients they despise.","TWN":"沒想到你還蠻鎮定的，有很多人都無法接受自己變得曾經輕視的病患一樣。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"열쇠를 운반하는 임무는 목숨을 다해서라도 마칠 각오였다.","JPN":"鍵を運ぶ任務は命をかけてでも果たす覚悟をしていた。","ENG":"I've already sworn to transport the Key, even if that means I have to die.","TWN":"我原本就下定決心，犧牲性命也要完全遷移鑰匙的任務。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런데 실패해 버린 지금은……","JPN":"だが、失敗してしまった今は……","ENG":"But now, seeing that I’ve failed...","TWN":"只是現在任務失敗…… "},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"내가 망령이 아니라 살아 있는 사람이란 실감이 나지 않아.","JPN":"私が亡霊ではなく、生きている人間なんだという実感が湧かないんだ。","ENG":"I can't believe that I'm still alive and haven’t turned into some ghost.","TWN":"好不真實的感覺，我竟然不是亡魂，而是活人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"충분히 살아 있다고 믿어도 좋아. 당신 덕에 많은 사람들이 하루를 더 살아가게 됐으니까.","JPN":"十分生きていると信じていいよ。あなたのおかげで多くの人がもう一日生きられるんだから。","ENG":"It's okay to believe that you're alive. Thanks to you, everyone else gets to live another day.","TWN":"你要相信你是活著的，而且有許多人因為你得以多活一天。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"격려 고맙군.","JPN":"励ましてくれてありがとう。","ENG":"Thanks for the encouragement.","TWN":"謝謝你的鼓勵。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 이런 몸으로 열쇠를 되찾고 명예를 회복할 수 있을지는 모르겠어.","JPN":"だが、こんな体で鍵を取り戻して名誉回復ができるかどうかはわからないな。","ENG":"But I'm not sure if I can get back the Key and restore my honor in this my condition.","TWN":"不過，我能用現在這副身體，找回鑰匙並恢復名聲嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"걱정 마. 침식환자는 여기서 많이 상대해 봤어.","JPN":"心配しないで。侵食患者はここでたくさん診てきたよ。","ENG":"Don't worry. I've taken care of a lot of patients with Corruption Syndrome.","TWN":"放心吧，我治療過許多侵蝕患者。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"명예를 회복하기 전까지는 쉽게 죽도록 내버려 두지 않을게.","JPN":"名誉を回復するまでは簡単に死なせないから。","ENG":"I won't let you die so easily until you've restored your honor.","TWN":"在你恢復名聲之前，我是不會輕易讓你死掉的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"말만으로도 고맙군.","JPN":"言葉だけでもありがたいな。","ENG":"I appreciate it.","TWN":"謝謝你。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"엘라 대장, 나 같은 환자가 수비대 일에 계속 관여해도 괜찮겠나?","JPN":"エラ隊長、私のような患者が守備隊の仕事に関わりつづけてもいいのか？","ENG":"Captain Ella, do you still think it's appropriate for a patient like me to get involved with the work of the Border Guards?","TWN":"艾拉隊長，那像我這樣的病患，還可以繼續參與護衛隊的工作嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"국경지대 주민들은 아이, 어른 할 거 없이 대부분 침식환자들이야.","JPN":"国境地帯の住民は老若男女を問わずほとんどが侵食患者だでね。","ENG":"Most of the villagers near the border, children and adults both, are affected by the Corruption.","TWN":"國境地區的居民，不管是大人或是小孩，大部分都是侵蝕患者。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"도시에 머물면 보균자 취급만 받는다는 현실을 받아들이고 여기 정착한 사람들이지.","JPN":"都市にいても保菌者扱いをされるだけだという現実を受け入れて、ここに定着したんだ。","ENG":"They've all settled down here after accepting the fact that they would only be treated as disease carriers if they stayed in the city.","TWN":"他們知道若是待在都市裡，只會被貼上帶原者的標籤，因此才定居在這裡。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그런 사람들이 국경에 모여 마을을 이루고, 수비대를 도와 주는 거야.","JPN":"そんな人たちが集まって国境に村を作り、守備隊を手伝ってくれてる。","ENG":"These people have gathered near the border, formed a village, and help out with guard duty.","TWN":"他們聚集在國境，形成村莊，並且幫助護衛隊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그러니 당신도 그렇게 해. 앞으로 내 지휘권은 당신에게 일임할 테니까.","JPN":"だからあなたもそうしたらいいよ。これから指揮権は一任するから。","ENG":"You should do that too. I'll even entrust you with commanding them from now on.","TWN":"你也可以，以後我的指揮權就交給你。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"지휘권을……? 어째서?","JPN":"指揮権を……？　なぜだ？","ENG":"Me, command...? But why?","TWN":"指揮權……？為什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"내가 대장직을 맡게 된 이유는 순전히 카운터라는 명함 때문이야.","JPN":"私が隊長になった理由は、単にカウンターだったから。","ENG":"The only reason I was appointed captain was because I'm a Counter.","TWN":"我之所以擔任隊長，只是因爲我是制裁者的關係。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"나에게 리더의 자질 같은 건 없어. 그런 교육도 받은 적 없고. 줄곧 흉내만 냈을 뿐이지.","JPN":"リーダーの資質なんてないよ。教わったこともないし。ずっと振りをしてきただけ。","ENG":"I have no leadership skills, nor did I get any training of that sort. I've just been pretending this whole time.","TWN":"我沒有資格擔任隊長，也沒有受過那種訓練，我只是在模仿一個隊長該有的樣子。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 당신은 달랐어.","JPN":"でもあなたはそうじゃなかった。","ENG":"But you're different.","TWN":"但你不一樣。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"병사들을 앞뒀을 때의 침착함. 상황을 정리하고 방향을 정하는 결단력. 모두 좋은 지휘관의 자질이었지.","JPN":"兵士たちの前で見せてくれた落ち着き。状況をまとめて、方向を決める決断力。全ていい指揮官が持つ資質。","ENG":"How you're calm in front of the soldiers, your fast decision-making, and organizing the situation. They're all qualities of a good commander.","TWN":"面對士兵時的臨危不亂，還有分析情勢後決定方向的判斷力，這些都是一位好的指揮官該有的特質。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"너무 경솔해. 지휘관이란 병사들의 신망이 있어야 하는 법이다.","JPN":"軽率すぎるな。指揮官とは兵士の信望がなければならないものだ。","ENG":"You're acting rashly. A commander is only as good as their soldiers' trust.","TWN":"這樣未免太過輕率，身為指揮官必須要取得士兵的信賴。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"갑자기 지휘권을 넘긴다고 자네 부하들이 내 말을 따를 것 같나?","JPN":"いきなり指揮権を任せるとして、君の部下が言うことを聞くと思うか？","ENG":"Do you think your troops will follow me just because you put me in charge?","TWN":"你以爲突然接交指揮權，你的部下就聽我的話嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"대원들은 전부 동의했어. 와트도 마찬가지고.","JPN":"隊員はみんな賛成してるよ。ワットもそうだし。","ENG":"The troops have already agreed to this. Even Watt.","TWN":"隊員們已經全數同意，連華特也同意。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"주민들은 어떨지 몰라도, 나와 내 대원들은 알아.","JPN":"住民はどうか知らないけど、私と私の隊員はわかるんだ。","ENG":"I don't know about the villagers, but I know Watt and my men.","TWN":"雖然不知道居民會有什麼反應，但我和我的隊員很清楚，"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지금 이 땅에 필요한 건 케케묵은 과거의 응어리가 아니라, 당신처럼 사람들을 지키기 위해 싸우는 군인이라는 걸.","JPN":"今この地に必要なのは古くさい過去のしこりじゃなくて、あなたのように人々を守るために戦う軍人だということが。","ENG":"What they need right now isn't some old resentment towards the past. They need a soldier like you who is willing to protect and fight for them.","TWN":"現在在這片土地需要的，不是過去的疙瘩，而是像你一樣為民而戰的軍人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제의를 수락하기 전에, 한 가지 물어봐도 될까?","JPN":"提案を受け入れる前に、一つだけ聞いてもいいか？","ENG":"Before I accept your offer, can I ask you a question?","TWN":"在接受你的提議之前，我可以問一件事嗎?"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"뭔데?","JPN":"何？","ENG":"What is it?","TWN":"什麼事？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"대장은 침식 증후군 환자도 아니고, 의사로서의 실력도 뛰어나.","JPN":"隊長は侵食症候群の患者でもなく、医者としての実力も優れている。","ENG":"You're not a patient with Corruption Syndrome, and you’re a skilled doctor.","TWN":"你既沒有侵蝕症候群，醫術也很精湛，"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그리고 성자… 아니, 카운터로서 남들보다 강력한 힘도 가졌지.","JPN":"そして聖者……いや、カウンターとして人より強力な力の持ち主だ。","ENG":"Plus, you're a Helgon... I mean, a Counter with incredible strength.","TWN":"又是聖者…不，是制裁者，能力比別人都好。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"왜 그런 인재가 제대로 된 지원도 받지 못하는 최전선에서 싸우는지 듣고 싶군.","JPN":"なぜそんな人材がちゃんとした支援もしてくれない最前線で戦ってるのか聞きたい。","ENG":"What I'm curious about is why someone like you is fighting on the frontlines without support.","TWN":"我想知道，為何這樣的人才會在得不到支援的最前線作戰。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……선택했을 뿐이야. 내가 최선이라고 생각하는 방향으로.","JPN":"……選んだだけだよ。私がベストだと思う方向を。","ENG":"Because I made a decision... for what I believe to be the best possible direction.","TWN":"……這是我的選擇，是我認為最好的選擇。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"원하는 걸 전부 이룰 순 없으니까.","JPN":"望むもの全てを実現することはできないから。","ENG":"We can't get everything we want.","TWN":"畢竟什麼事都能如願。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"카운터로 각성한 사람으로서의 책무 같은 건가?","JPN":"カウンターとして覚醒した者としての責務のようなものなのか？","ENG":"Is that like a duty for someone who has awakened as a Counter?","TWN":"這是身為一個覺醒成制裁者的人要擔負的責任嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"거창하게 표현할 필요 없어.","JPN":"そんなに大げさなことじゃないよ。","ENG":"There's no need to express it like that.","TWN":"沒這麼誇張。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"처음엔 그저 침식으로 고통 받는 사람들을 구하고 싶었을 뿐이야. 그래서 사람을 살리는 법을 배웠지.","JPN":"最初はただ侵食で苦しんでる人たちを助けたかっただけ。だから人を治療する方法を勉強したんだ。","ENG":"At first, I just wanted to help those who were suffering from the Corruption. That's why I became a doctor.","TWN":"當初我之所以學醫，只是因為想救那些為侵蝕所苦的人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 결국 지키고 싶었던 사람은 죽고, 나는 카운터가 됐어.","JPN":"でも結局守りたかった人は死んで、私はカウンターになった。","ENG":"But after the person who I tried to save died, I became a Counter.","TWN":"不過後來我想保護的人死了，我就成了制裁者。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이 힘으로 침식체를 없애면 침식 증후군에 고통 받는 사람들도 줄어들지 않을까…….","JPN":"この力で侵食体をなくせば、侵食症候群に苦しめられている人も減るんじゃないかって……","ENG":"\\"Will eliminating C.O.s with this power reduce the number of people suffering from the Corruption Syndrome...?\\"","TWN":"我心想，若是能用這股能來消滅侵蝕體，那為侵蝕症候群所苦的人也會減少吧……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그런 막연한 생각으로 여기까지 와서, 당신도 구해 버린 거야.","JPN":"そういう漠然とした思いでここまで来て、あなたも助けちゃった。","ENG":"I came here with that vague idea in my head and ended up saving you as well.","TWN":"我抱持著這種不確定的想法直到如今，也因此才會救你。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리고 오늘을 기점으로 이 자리에 어울리는 사람은 나보다 당신이란 확신이 들었지.","JPN":"そして今日をもって、私よりあなたの方が隊長の職に適していると確信したんだよ。","ENG":"And as of today, I'm convinced that you’re better suited to serve in this position than I am.","TWN":"而現在，我確定適合坐上這個位置的人是你，不是我。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇군. 혹시나 지휘권을 넘기는 다른 이유가 있나 해서 말이야.","JPN":"そうか。指揮権を譲る理由が別にあるんじゃないかと思ったんだが。","ENG":"I see. I was just asking if there was some other reason behind your decision.","TWN":"原來如此，我還以為你交出指揮權是有其他原因。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"왜? 내가 당신에게 일을 떠넘기고 도망치기라도 할 줄 알았어?","JPN":"何？　あなたに仕事を押しつけて逃げるとでも思った？","ENG":"Why? Did you expect that I was going to delegate everything to you and run away?","TWN":"怎麼？你以爲我是想把責任推給你，然後自己跑掉嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아니. 혹시나 대장이 연심에 사로잡혀 날 너무 믿는 것 아닌가 걱정했거든.","JPN":"いや。ひょっとして、隊長は恋心のあまり私を信じすぎているんじゃないかと心配したんだ。","ENG":"No, I was afraid you were attracted by me, which is why you're so trusting of me right now, Captain.","TWN":"不是，我擔心你是不是愛上我，才會如此信任我。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…크헉!","JPN":"……くはっ！","ENG":"Kuh!!","TWN":"…咳咳！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이전에도 느꼈지만 사람이 참 뻔뻔하네.","JPN":"前にも思ったけど、あなたは本当に身の程しらずだね。","ENG":"I knew you were shameless, but not this much.","TWN":"我之前就覺得你真的很厚臉皮。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"으윽……. 의사가 환자를 때려도 되는 건가?","JPN":"ぐうっ……医者が患者を殴っていいのか？","ENG":"Ngh... What kind of a doctor punches her own patients?","TWN":"呃……醫生可以打病人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"특정 정신질환을 치료하는 데에는 충격요법이 효과적이야. 이를테면 자의식 과잉 같은 거.","JPN":"特定の精神病を治療するには衝撃療法が効果的なんだ。例えば自意識過剰とか。","ENG":"Haven't you heard of shock therapy? I heard it's effective on patients with mental illnesses, as well as narcissists like yourself.","TWN":"衝擊療法對治療特定的精神疾病很有效，譬如自我感覺良好之類的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"곧 식사 시간이야. 헛소리에 기운 빼지 말고 배나 채워.","JPN":"もうすぐ食事の時間よ。戯言はやめて腹でも満たして。","ENG":"It's almost time for supper. Let's cut the crap and go eat.","TWN":"要吃了飯，有力氣胡說八道，不如快去填飽肚子吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이 냄새… 이번에도 감자인가?","JPN":"この匂い……今度もジャガイモなのか？","ENG":"That smell... Is it potatoes again?","TWN":"這個味道…今天也是吃馬鈴薯嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"맞아. 앞으로도 실컷 먹을 테니 하루 빨리 익숙해지도록 해.","JPN":"そうだ。これからも飽きるほど食べなきゃならないんだから、一日も早く慣れるといいね。","ENG":"Yes. You're going to be eating a lot of it, so get used to it.","TWN":"沒錯，以後也會繼續吃，勸你趕快習慣吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지휘관.","JPN":"指揮官。","ENG":"Commander.","TWN":"指揮官。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};